import React from 'react';
import { NavLink } from 'react-router-dom';
import { complaintCategories } from './complaintCategories';

const ComplaintsLayout = () => {
  return (
    <div className="p-6 space-y-6">
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
        <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Complaints</h1>
            <p className="mt-2 text-sm text-gray-500">Browse all complaint categories and drill into the type you need.</p>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            <NavLink
              to="/complaints"
              end
              className={({ isActive }) =>
                `px-4 py-2 rounded-full text-sm font-semibold transition ${isActive ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`
              }
            >
              All
            </NavLink>
            {complaintCategories.map((category) => (
              <NavLink
                key={category.key}
                to={`/complaints/category/${category.slug}`}
                className={({ isActive }) =>
                  `px-4 py-2 rounded-full text-sm font-semibold transition ${isActive ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`
                }
              >
                {category.label}
              </NavLink>
            ))}
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <Outlet />
      </div>
    </div>
  );
};

export default ComplaintsLayout;
